:root {
    --bg: #0b1220;
    --bg-soft: #111a2e;
    --panel: rgba(255, 255, 255, 0.06);
    --panel-solid: #121c2f;
    --panel-strong: #17243d;
    --border: rgba(255, 255, 255, 0.10);
    --text: #e5eefc;
    --muted: #9fb1d1;
    --primary: #4f8cff;
    --primary-2: #6ea8ff;
    --success: #26c281;
    --warning: #f5a524;
    --danger: #ff5d5d;
    --shadow: 0 20px 60px rgba(0, 0, 0, 0.35);
    --radius-xl: 24px;
    --radius-lg: 18px;
    --radius-md: 14px;
    --radius-sm: 10px;

    /* Light mode variables */
    --light-bg: #f8fafc;
    --light-bg-soft: #f1f5f9;
    --light-panel: rgba(255, 255, 255, 0.9);
    --light-panel-solid: #ffffff;
    --light-border: rgba(0, 0, 0, 0.10);
    --light-text: #1e293b;
    --light-muted: #64748b;
}

* {
    box-sizing: border-box;
}

html, body {
    margin: 0;
    padding: 0;
    min-height: 100%;
}

body {
    font-family: 'Inter', sans-serif;
    background:
        radial-gradient(circle at top left, rgba(79, 140, 255, 0.22), transparent 30%),
        radial-gradient(circle at bottom right, rgba(38, 194, 129, 0.14), transparent 28%),
        linear-gradient(180deg, #08101d 0%, #0b1220 100%);
    color: var(--text);
    transition: background 0.3s ease, color 0.3s ease;
}

body.light-mode {
    background:
        radial-gradient(circle at top left, rgba(79, 140, 255, 0.08), transparent 30%),
        radial-gradient(circle at bottom right, rgba(38, 194, 129, 0.06), transparent 28%),
        linear-gradient(180deg, #f8fafc 0%, #f1f5f9 100%);
    color: var(--light-text);
}

body.light-mode .card,
body.light-mode .question-card,
body.light-mode .question-block,
body.light-mode .stat-box,
body.light-mode .mcq-option {
    background: rgba(255, 255, 255, 0.9);
    border-color: var(--light-border);
}

body.light-mode .topbar {
    background: rgba(255, 255, 255, 0.9);
    border-color: var(--light-border);
}

body.light-mode input,
body.light-mode textarea,
body.light-mode select {
    background: rgba(255, 255, 255, 0.9);
    border-color: var(--light-border);
    color: var(--light-text);
}

body.light-mode label {
    color: var(--light-text);
}

body.light-mode .muted {
    color: var(--light-muted);
}

body.light-mode .brand-subtitle {
    color: var(--light-muted);
}

a {
    color: inherit;
    text-decoration: none;
}

.app-shell {
    min-height: 100vh;
}

.topbar {
    position: sticky;
    top: 0;
    z-index: 20;
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 20px;
    padding: 18px 26px;
    backdrop-filter: blur(14px);
    background: rgba(10, 15, 28, 0.78);
    border-bottom: 1px solid var(--border);
}

.brand {
    display: flex;
    align-items: center;
    gap: 14px;
}

.brand-mark {
    width: 46px;
    height: 46px;
    border-radius: 14px;
    display: grid;
    place-items: center;
    font-weight: 800;
    color: white;
    background: linear-gradient(135deg, var(--primary), var(--primary-2));
    box-shadow: 0 12px 28px rgba(79, 140, 255, 0.35);
}

.brand-title {
    font-size: 1.02rem;
    font-weight: 800;
    letter-spacing: 0.2px;
}

.brand-subtitle {
    font-size: 0.82rem;
    color: var(--muted);
    margin-top: 3px;
}

.nav {
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
}

.nav a {
    padding: 10px 14px;
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    color: var(--text);
    font-weight: 600;
    transition: 0.2s ease;
}

.nav a:hover {
    background: rgba(255, 255, 255, 0.08);
    transform: translateY(-1px);
}

.page-wrap {
    max-width: 1280px;
    margin: 0 auto;
    padding: 28px 20px 40px;
}

.flash-stack {
    display: grid;
    gap: 12px;
    margin-bottom: 18px;
}

.flash-message {
    padding: 14px 16px;
    border-radius: var(--radius-md);
    background: rgba(79, 140, 255, 0.12);
    border: 1px solid rgba(79, 140, 255, 0.22);
    color: var(--text);
    box-shadow: var(--shadow);
}

.card {
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid var(--border);
    border-radius: var(--radius-xl);
    padding: 24px;
    box-shadow: var(--shadow);
    backdrop-filter: blur(18px);
}

.card + .card {
    margin-top: 18px;
}

.card.narrow {
    max-width: 760px;
    margin: 0 auto;
}

.card.inner {
    background: rgba(255, 255, 255, 0.04);
    border-radius: var(--radius-lg);
    margin-top: 16px;
    box-shadow: none;
}

h1, h2, h3 {
    margin-top: 0;
    line-height: 1.2;
}

h1 {
    font-size: clamp(2rem, 3vw, 3rem);
    margin-bottom: 8px;
}

h2 {
    font-size: 1.35rem;
    margin-bottom: 14px;
}

h3 {
    font-size: 1.1rem;
    margin-bottom: 10px;
}

.muted {
    color: var(--muted);
}

.form-grid,
.grid-2 {
    display: grid;
    gap: 16px;
}

.grid-2 {
    grid-template-columns: repeat(2, minmax(0, 1fr));
}

label {
    display: block;
    margin-bottom: 8px;
    font-weight: 600;
    color: #dce7fa;
}

input, textarea, select {
    width: 100%;
    border: 1px solid rgba(255, 255, 255, 0.10);
    background: rgba(7, 13, 24, 0.72);
    color: var(--text);
    border-radius: 14px;
    padding: 13px 14px;
    font: inherit;
    outline: none;
    transition: 0.2s ease;
}

input:focus, textarea:focus, select:focus {
    border-color: rgba(79, 140, 255, 0.8);
    box-shadow: 0 0 0 4px rgba(79, 140, 255, 0.14);
}

textarea {
    resize: vertical;
    min-height: 120px;
}

.btn, button {
    appearance: none;
    border: none;
    cursor: pointer;
    border-radius: 14px;
    padding: 12px 16px;
    font: inherit;
    font-weight: 700;
    transition: 0.2s ease;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
}

.btn:hover, button:hover {
    transform: translateY(-1px);
}

.btn.primary {
    color: white;
    background: linear-gradient(135deg, var(--primary), var(--primary-2));
    box-shadow: 0 12px 28px rgba(79, 140, 255, 0.26);
}

.btn.secondary {
    color: var(--text);
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid var(--border);
}

.btn.danger {
    color: white;
    background: linear-gradient(135deg, #ff6b6b, #ff4b5f);
}

.btn.small {
    padding: 9px 13px;
    border-radius: 12px;
    font-size: 0.92rem;
}

.row-between {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 14px;
    flex-wrap: wrap;
}

.stats {
    display: grid;
    grid-template-columns: repeat(4, minmax(0, 1fr));
    gap: 14px;
    margin-top: 18px;
}

.stat-box {
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 18px;
}

.table-wrap {
    overflow-x: auto;
    border-radius: var(--radius-lg);
}

table {
    width: 100%;
    border-collapse: collapse;
    min-width: 950px;
    overflow: hidden;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
}

th, td {
    padding: 14px 16px;
    text-align: left;
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
    vertical-align: top;
}

th {
    color: #dbe6ff;
    font-size: 0.92rem;
    background: rgba(255, 255, 255, 0.04);
}

.badge {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 7px 11px;
    border-radius: 999px;
    font-size: 0.8rem;
    font-weight: 700;
    background: rgba(79, 140, 255, 0.12);
    border: 1px solid rgba(79, 140, 255, 0.18);
}

.badge.active {
    background: rgba(38, 194, 129, 0.14);
    border-color: rgba(38, 194, 129, 0.22);
}

.badge.draft {
    background: rgba(245, 165, 36, 0.14);
    border-color: rgba(245, 165, 36, 0.22);
}

.badge.closed {
    background: rgba(255, 93, 93, 0.12);
    border-color: rgba(255, 93, 93, 0.18);
}

.question-card,
.question-block {
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 18px;
    margin-bottom: 16px;
}

.answer-box {
    margin-top: 14px;
    padding: 16px;
    border-radius: 16px;
    background: rgba(0, 0, 0, 0.18);
    border: 1px solid rgba(255, 255, 255, 0.08);
}

.answer-text {
    margin-top: 8px;
    white-space: pre-wrap;
    color: #d7e4ff;
}

.checkbox-line {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-top: 14px;
}

.checkbox-line input {
    width: auto;
}

.mcq-list {
    display: grid;
    gap: 12px;
    margin-top: 14px;
}

.mcq-option {
    display: flex;
    gap: 12px;
    align-items: center;
    padding: 14px 16px;
    border-radius: 14px;
    border: 1px solid var(--border);
    background: rgba(255, 255, 255, 0.04);
}

.mcq-option:hover {
    background: rgba(255, 255, 255, 0.07);
}

.mcq-option input {
    width: auto;
}

.exam-shell {
    max-width: 1280px;
    margin: 0 auto;
}

.exam-topbar {
    position: sticky;
    top: 84px;
    z-index: 10;
    display: grid;
    grid-template-columns: 1.5fr 0.7fr 1fr;
    gap: 16px;
    align-items: center;
    margin-bottom: 18px;
    padding: 20px;
    border-radius: var(--radius-xl);
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid var(--border);
    box-shadow: var(--shadow);
    backdrop-filter: blur(18px);
}

.timer-box {
    padding: 18px;
    text-align: center;
    border-radius: 18px;
    background: linear-gradient(135deg, rgba(79, 140, 255, 0.18), rgba(110, 168, 255, 0.10));
    border: 1px solid rgba(79, 140, 255, 0.20);
}

.timer-box #timer {
    margin-top: 6px;
    font-size: 2rem;
    font-weight: 800;
    letter-spacing: 0.5px;
}

.loader {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    border: 4px solid rgba(255, 255, 255, 0.12);
    border-top-color: var(--primary);
    animation: spin 1s linear infinite;
    margin-top: 14px;
}

/* Enhanced loaders */
.loader-small {
    width: 24px;
    height: 24px;
    border-width: 3px;
}

.loader-large {
    width: 64px;
    height: 64px;
    border-width: 5px;
}

/* Dots loader */
.loader-dots {
    display: flex;
    gap: 8px;
    justify-content: center;
    align-items: center;
}

.loader-dots span {
    width: 12px;
    height: 12px;
    border-radius: 50%;
    background: var(--primary);
    animation: bounce 1.4s ease-in-out infinite;
}

.loader-dots span:nth-child(1) { animation-delay: -0.32s; }
.loader-dots span:nth-child(2) { animation-delay: -0.16s; }

@keyframes bounce {
    0%, 80%, 100% { transform: scale(0); }
    40% { transform: scale(1); }
}

/* Pulse loader */
.loader-pulse {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    background: var(--primary);
    animation: pulse 1.5s ease-in-out infinite;
}

@keyframes pulse {
    0% { transform: scale(0.95); opacity: 1; }
    50% { transform: scale(1.1); opacity: 0.7; }
    100% { transform: scale(0.95); opacity: 1; }
}

/* Skeleton loading */
.skeleton {
    background: linear-gradient(90deg, rgba(255,255,255,0.05) 25%, rgba(255,255,255,0.1) 50%, rgba(255,255,255,0.05) 75%);
    background-size: 200% 100%;
    animation: shimmer 1.5s infinite;
    border-radius: 8px;
}

@keyframes shimmer {
    0% { background-position: 200% 0; }
    100% { background-position: -200% 0; }
}

.skeleton-text {
    height: 16px;
    margin-bottom: 8px;
}

.skeleton-title {
    height: 28px;
    width: 60%;
    margin-bottom: 16px;
}

.skeleton-card {
    height: 120px;
    margin-bottom: 16px;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

.actions {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
}

/* Toast notifications */
.toast-container {
    position: fixed;
    top: 20px;
    right: 20px;
    z-index: 1000;
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.toast {
    min-width: 300px;
    padding: 16px 20px;
    border-radius: var(--radius-lg);
    background: rgba(255, 255, 255, 0.95);
    border: 1px solid var(--border);
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
    backdrop-filter: blur(10px);
    animation: slideIn 0.3s ease;
    display: flex;
    align-items: center;
    gap: 12px;
    color: var(--text);
}

.toast.success {
    border-left: 4px solid var(--success);
}

.toast.error {
    border-left: 4px solid var(--danger);
}

.toast.warning {
    border-left: 4px solid var(--warning);
}

.toast.info {
    border-left: 4px solid var(--primary);
}

.toast.hiding {
    animation: slideOut 0.3s ease forwards;
}

@keyframes slideIn {
    from {
        transform: translateX(400px);
        opacity: 0;
    }
    to {
        transform: translateX(0);
        opacity: 1;
    }
}

@keyframes slideOut {
    from {
        transform: translateX(0);
        opacity: 1;
    }
    to {
        transform: translateX(400px);
        opacity: 0;
    }
}

/* Enhanced card animations */
.card {
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid var(--border);
    border-radius: var(--radius-xl);
    padding: 24px;
    box-shadow: var(--shadow);
    backdrop-filter: blur(18px);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.card:hover {
    transform: translateY(-4px);
    box-shadow: 0 24px 72px rgba(0, 0, 0, 0.45);
}

/* Progress bar */
.progress-bar {
    width: 100%;
    height: 8px;
    background: rgba(255, 255, 255, 0.1);
    border-radius: 999px;
    overflow: hidden;
}

.progress-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--primary), var(--primary-2));
    border-radius: 999px;
    transition: width 0.5s ease;
    animation: progressGlow 2s ease-in-out infinite;
}

@keyframes progressGlow {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.8; }
}

/* Question palette */
.question-palette {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(48px, 1fr));
    gap: 8px;
    padding: 16px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    margin-bottom: 20px;
}

.palette-item {
    width: 48px;
    height: 48px;
    border-radius: 12px;
    display: grid;
    place-items: center;
    font-weight: 700;
    font-size: 0.9rem;
    cursor: pointer;
    transition: all 0.2s ease;
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid var(--border);
    color: var(--text);
}

.palette-item:hover {
    transform: scale(1.1);
    background: rgba(255, 255, 255, 0.1);
}

.palette-item.answered {
    background: rgba(38, 194, 129, 0.2);
    border-color: var(--success);
    color: var(--success);
}

.palette-item.review {
    background: rgba(245, 165, 36, 0.2);
    border-color: var(--warning);
    color: var(--warning);
}

.palette-item.current {
    background: var(--primary);
    border-color: var(--primary);
    color: white;
    transform: scale(1.1);
}

.palette-item.visited {
    background: rgba(79, 140, 255, 0.15);
    border-color: var(--primary);
}

/* Word counter */
.word-counter {
    text-align: right;
    font-size: 0.85rem;
    color: var(--muted);
    margin-top: 6px;
}

.word-counter.warning {
    color: var(--warning);
}

.word-counter.danger {
    color: var(--danger);
}

/* Timer states */
.timer-box.warning {
    background: linear-gradient(135deg, rgba(245, 165, 36, 0.18), rgba(250, 180, 50, 0.10));
    border-color: rgba(245, 165, 36, 0.30);
    animation: pulse 1s ease-in-out infinite;
}

.timer-box.danger {
    background: linear-gradient(135deg, rgba(255, 93, 93, 0.18), rgba(255, 70, 70, 0.10));
    border-color: rgba(255, 93, 93, 0.30);
    animation: urgentPulse 0.5s ease-in-out infinite;
}

@keyframes urgentPulse {
    0%, 100% { transform: scale(1); }
    50% { transform: scale(1.05); }
}

/* Auto-save indicator */
.auto-save-indicator {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    font-size: 0.85rem;
    color: var(--muted);
    padding: 6px 12px;
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    transition: all 0.3s ease;
}

.auto-save-indicator.saving {
    color: var(--primary);
    border-color: rgba(79, 140, 255, 0.3);
}

.auto-save-indicator.saved {
    color: var(--success);
    border-color: rgba(38, 194, 129, 0.3);
}

/* Theme toggle button */
.theme-toggle {
    width: 44px;
    height: 44px;
    border-radius: 12px;
    display: grid;
    place-items: center;
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid var(--border);
    cursor: pointer;
    transition: all 0.3s ease;
    color: var(--text);
}

.theme-toggle:hover {
    background: rgba(255, 255, 255, 0.1);
    transform: rotate(180deg);
}

/* Mobile menu */
.mobile-menu-btn {
    display: none;
    width: 44px;
    height: 44px;
    border-radius: 12px;
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid var(--border);
    cursor: pointer;
    align-items: center;
    justify-content: center;
    gap: 6px;
    flex-direction: column;
}

.mobile-menu-btn span {
    width: 20px;
    height: 2px;
    background: var(--text);
    border-radius: 2px;
    transition: all 0.3s ease;
}

/* Page transitions */
.page-transition {
    animation: fadeIn 0.4s ease;
}

@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Button ripple effect */
.btn {
    position: relative;
    overflow: hidden;
}

.btn::after {
    content: '';
    position: absolute;
    top: 50%;
    left: 50%;
    width: 0;
    height: 0;
    background: rgba(255, 255, 255, 0.3);
    border-radius: 50%;
    transform: translate(-50%, -50%);
    transition: width 0.6s, height 0.6s;
}

.btn:active::after {
    width: 300px;
    height: 300px;
}

/* Stat card enhancements */
.stat-box {
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 18px;
    transition: all 0.3s ease;
}

.stat-box:hover {
    transform: translateY(-4px);
    background: rgba(255, 255, 255, 0.08);
    border-color: rgba(79, 140, 255, 0.3);
}

.stat-value {
    font-size: 2rem;
    font-weight: 800;
    margin: 8px 0;
    background: linear-gradient(135deg, var(--primary), var(--primary-2));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.stat-label {
    font-size: 0.9rem;
    color: var(--muted);
}

/* Chart container */
.chart-container {
    position: relative;
    height: 300px;
    margin-top: 20px;
}

/* Violation timeline */
.violation-timeline {
    position: relative;
    padding-left: 30px;
}

.violation-timeline::before {
    content: '';
    position: absolute;
    left: 8px;
    top: 0;
    bottom: 0;
    width: 2px;
    background: var(--border);
}

.violation-item {
    position: relative;
    padding: 12px 16px;
    margin-bottom: 12px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    border-radius: var(--radius-md);
}

.violation-item::before {
    content: '';
    position: absolute;
    left: -22px;
    top: 50%;
    transform: translateY(-50%);
    width: 12px;
    height: 12px;
    border-radius: 50%;
    background: var(--danger);
    border: 2px solid var(--bg);
}

.violation-item.warning::before {
    background: var(--warning);
}

.violation-time {
    font-size: 0.85rem;
    color: var(--muted);
    margin-bottom: 4px;
}

/* Activity feed */
.activity-feed {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.activity-item {
    display: flex;
    gap: 12px;
    padding: 12px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    border-radius: var(--radius-md);
    transition: all 0.2s ease;
}

.activity-item:hover {
    background: rgba(255, 255, 255, 0.06);
}

.activity-icon {
    width: 40px;
    height: 40px;
    border-radius: 10px;
    display: grid;
    place-items: center;
    background: rgba(79, 140, 255, 0.15);
    color: var(--primary);
    font-weight: 700;
    flex-shrink: 0;
}

.activity-content {
    flex: 1;
}

.activity-title {
    font-weight: 600;
    margin-bottom: 4px;
}

.activity-time {
    font-size: 0.85rem;
    color: var(--muted);
}

/* Search input */
.search-input {
    position: relative;
}

.search-input input {
    padding-left: 44px;
}

.search-input::before {
    content: '';
    position: absolute;
    left: 14px;
    top: 50%;
    transform: translateY(-50%);
    font-size: 1rem;
}

/* Dropdown */
.dropdown {
    position: relative;
    display: inline-block;
}

.dropdown-menu {
    position: absolute;
    top: 100%;
    right: 0;
    min-width: 200px;
    padding: 8px 0;
    background: rgba(255, 255, 255, 0.95);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow);
    backdrop-filter: blur(10px);
    opacity: 0;
    visibility: hidden;
    transform: translateY(-10px);
    transition: all 0.2s ease;
    z-index: 100;
}

.dropdown.active .dropdown-menu {
    opacity: 1;
    visibility: visible;
    transform: translateY(8px);
}

.dropdown-item {
    padding: 10px 16px;
    cursor: pointer;
    transition: background 0.2s ease;
    color: var(--text);
}

.dropdown-item:hover {
    background: rgba(79, 140, 255, 0.1);
}

.dropdown-divider {
    height: 1px;
    background: var(--border);
    margin: 8px 0;
}

/* Modal */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.7);
    backdrop-filter: blur(4px);
    display: grid;
    place-items: center;
    z-index: 1000;
    opacity: 0;
    visibility: hidden;
    transition: all 0.3s ease;
}

.modal-overlay.active {
    opacity: 1;
    visibility: visible;
}

.modal {
    background: var(--panel-solid);
    border: 1px solid var(--border);
    border-radius: var(--radius-xl);
    padding: 32px;
    max-width: 500px;
    width: 90%;
    transform: scale(0.9);
    transition: transform 0.3s ease;
}

.modal-overlay.active .modal {
    transform: scale(1);
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 20px;
}

.modal-close {
    width: 36px;
    height: 36px;
    border-radius: 10px;
    display: grid;
    place-items: center;
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid var(--border);
    cursor: pointer;
    transition: all 0.2s ease;
}

.modal-close:hover {
    background: rgba(255, 93, 93, 0.2);
    border-color: var(--danger);
}

/* Tabs */
.tabs {
    display: flex;
    gap: 4px;
    padding: 4px;
    background: rgba(255, 255, 255, 0.04);
    border-radius: var(--radius-lg);
    margin-bottom: 20px;
}

.tab {
    flex: 1;
    padding: 12px 16px;
    border-radius: var(--radius-md);
    text-align: center;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s ease;
    color: var(--muted);
}

.tab:hover {
    color: var(--text);
}

.tab.active {
    background: var(--primary);
    color: white;
}

/* Tooltip */
.tooltip {
    position: relative;
}

.tooltip::after {
    content: attr(data-tooltip);
    position: absolute;
    bottom: 100%;
    left: 50%;
    transform: translateX(-50%) translateY(-8px);
    padding: 8px 12px;
    background: rgba(0, 0, 0, 0.9);
    color: white;
    font-size: 0.85rem;
    border-radius: 8px;
    white-space: nowrap;
    opacity: 0;
    visibility: hidden;
    transition: all 0.2s ease;
    z-index: 100;
}

.tooltip:hover::after {
    opacity: 1;
    visibility: visible;
    transform: translateX(-50%) translateY(-4px);
}

/* Badge enhancements */
.badge {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 7px 11px;
    border-radius: 999px;
    font-size: 0.8rem;
    font-weight: 700;
    background: rgba(79, 140, 255, 0.12);
    border: 1px solid rgba(79, 140, 255, 0.18);
    transition: all 0.2s ease;
}

.badge:hover {
    transform: scale(1.05);
}

.badge.active {
    background: rgba(38, 194, 129, 0.14);
    border-color: rgba(38, 194, 129, 0.22);
}

.badge.draft {
    background: rgba(245, 165, 36, 0.14);
    border-color: rgba(245, 165, 36, 0.22);
}

.badge.closed {
    background: rgba(255, 93, 93, 0.12);
    border-color: rgba(255, 93, 93, 0.18);
}

@media (max-width: 980px) {
    .grid-2,
    .stats,
    .exam-topbar {
        grid-template-columns: 1fr;
    }

    .topbar {
        flex-direction: column;
        align-items: flex-start;
    }

    .nav {
        width: 100%;
    }
}

@media (max-width: 640px) {
    .page-wrap {
        padding: 18px 14px 28px;
    }

    .card {
        padding: 18px;
        border-radius: 18px;
    }

    .topbar {
        padding: 16px 14px;
    }

    .timer-box #timer {
        font-size: 1.6rem;
    }
}

:root {
    --bg: #0b1220;
    --bg-soft: #111a2e;
    --panel: rgba(255, 255, 255, 0.06);
    --panel-solid: #121c2f;
    --panel-strong: #17243d;
    --border: rgba(255, 255, 255, 0.10);
    --text: #e5eefc;
    --muted: #9fb1d1;
    --primary: #4f8cff;
    --primary-2: #6ea8ff;
    --success: #26c281;
    --warning: #f5a524;
    --danger: #ff5d5d;
    --shadow: 0 20px 60px rgba(0, 0, 0, 0.35);
    --radius-xl: 24px;
    --radius-lg: 18px;
    --radius-md: 14px;
    --radius-sm: 10px;

    /* Light mode variables */
    --light-bg: #f8fafc;
    --light-bg-soft: #f1f5f9;
    --light-panel: rgba(255, 255, 255, 0.9);
    --light-panel-solid: #ffffff;
    --light-border: rgba(0, 0, 0, 0.10);
    --light-text: #1e293b;
    --light-muted: #64748b;
}

* {
    box-sizing: border-box;
}

html, body {
    margin: 0;
    padding: 0;
    min-height: 100%;
}

body {
    font-family: 'Inter', sans-serif;
    background:
        radial-gradient(circle at top left, rgba(79, 140, 255, 0.22), transparent 30%),
        radial-gradient(circle at bottom right, rgba(38, 194, 129, 0.14), transparent 28%),
        linear-gradient(180deg, #08101d 0%, #0b1220 100%);
    color: var(--text);
    transition: background 0.3s ease, color 0.3s ease;
}

body.light-mode {
    background:
        radial-gradient(circle at top left, rgba(79, 140, 255, 0.08), transparent 30%),
        radial-gradient(circle at bottom right, rgba(38, 194, 129, 0.06), transparent 28%),
        linear-gradient(180deg, #f8fafc 0%, #f1f5f9 100%);
    color: var(--light-text);
}

body.light-mode .card,
body.light-mode .question-card,
body.light-mode .question-block,
body.light-mode .stat-box,
body.light-mode .mcq-option {
    background: rgba(255, 255, 255, 0.9);
    border-color: var(--light-border);
}

body.light-mode .topbar {
    background: rgba(255, 255, 255, 0.9);
    border-color: var(--light-border);
}

body.light-mode input,
body.light-mode textarea,
body.light-mode select {
    background: rgba(255, 255, 255, 0.9);
    border-color: var(--light-border);
    color: var(--light-text);
}

body.light-mode label {
    color: var(--light-text);
}

body.light-mode .muted {
    color: var(--light-muted);
}

body.light-mode .brand-subtitle {
    color: var(--light-muted);
}

a {
    color: inherit;
    text-decoration: none;
}

.app-shell {
    min-height: 100vh;
}

.topbar {
    position: sticky;
    top: 0;
    z-index: 20;
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 20px;
    padding: 18px 26px;
    backdrop-filter: blur(14px);
    background: rgba(10, 15, 28, 0.78);
    border-bottom: 1px solid var(--border);
}

.brand {
    display: flex;
    align-items: center;
    gap: 14px;
}

.brand-mark {
    width: 46px;
    height: 46px;
    border-radius: 14px;
    display: grid;
    place-items: center;
    font-weight: 800;
    color: white;
    background: linear-gradient(135deg, var(--primary), var(--primary-2));
    box-shadow: 0 12px 28px rgba(79, 140, 255, 0.35);
}

.brand-title {
    font-size: 1.02rem;
    font-weight: 800;
    letter-spacing: 0.2px;
}

.brand-subtitle {
    font-size: 0.82rem;
    color: var(--muted);
    margin-top: 3px;
}

.nav {
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
}

.nav a {
    padding: 10px 14px;
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    color: var(--text);
    font-weight: 600;
    transition: 0.2s ease;
}

.nav a:hover {
    background: rgba(255, 255, 255, 0.08);
    transform: translateY(-1px);
}

.page-wrap {
    max-width: 1280px;
    margin: 0 auto;
    padding: 28px 20px 40px;
}

.flash-stack {
    display: grid;
    gap: 12px;
    margin-bottom: 18px;
}

.flash-message {
    padding: 14px 16px;
    border-radius: var(--radius-md);
    background: rgba(79, 140, 255, 0.12);
    border: 1px solid rgba(79, 140, 255, 0.22);
    color: var(--text);
    box-shadow: var(--shadow);
}

.card {
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid var(--border);
    border-radius: var(--radius-xl);
    padding: 24px;
    box-shadow: var(--shadow);
    backdrop-filter: blur(18px);
}

.card + .card {
    margin-top: 18px;
}

.card.narrow {
    max-width: 760px;
    margin: 0 auto;
}

.card.inner {
    background: rgba(255, 255, 255, 0.04);
    border-radius: var(--radius-lg);
    margin-top: 16px;
    box-shadow: none;
}

h1, h2, h3 {
    margin-top: 0;
    line-height: 1.2;
}

h1 {
    font-size: clamp(2rem, 3vw, 3rem);
    margin-bottom: 8px;
}

h2 {
    font-size: 1.35rem;
    margin-bottom: 14px;
}

h3 {
    font-size: 1.1rem;
    margin-bottom: 10px;
}

.muted {
    color: var(--muted);
}

.form-grid,
.grid-2 {
    display: grid;
    gap: 16px;
}

.grid-2 {
    grid-template-columns: repeat(2, minmax(0, 1fr));
}

label {
    display: block;
    margin-bottom: 8px;
    font-weight: 600;
    color: #dce7fa;
}

input, textarea, select {
    width: 100%;
    border: 1px solid rgba(255, 255, 255, 0.10);
    background: rgba(7, 13, 24, 0.72);
    color: var(--text);
    border-radius: 14px;
    padding: 13px 14px;
    font: inherit;
    outline: none;
    transition: 0.2s ease;
}

input:focus, textarea:focus, select:focus {
    border-color: rgba(79, 140, 255, 0.8);
    box-shadow: 0 0 0 4px rgba(79, 140, 255, 0.14);
}

textarea {
    resize: vertical;
    min-height: 120px;
}

.btn, button {
    appearance: none;
    border: none;
    cursor: pointer;
    border-radius: 14px;
    padding: 12px 16px;
    font: inherit;
    font-weight: 700;
    transition: 0.2s ease;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
}

.btn:hover, button:hover {
    transform: translateY(-1px);
}

.btn.primary {
    color: white;
    background: linear-gradient(135deg, var(--primary), var(--primary-2));
    box-shadow: 0 12px 28px rgba(79, 140, 255, 0.26);
}

.btn.secondary {
    color: var(--text);
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid var(--border);
}

.btn.danger {
    color: white;
    background: linear-gradient(135deg, #ff6b6b, #ff4b5f);
}

.btn.small {
    padding: 9px 13px;
    border-radius: 12px;
    font-size: 0.92rem;
}

.row-between {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 14px;
    flex-wrap: wrap;
}

.stats {
    display: grid;
    grid-template-columns: repeat(4, minmax(0, 1fr));
    gap: 14px;
    margin-top: 18px;
}

.stat-box {
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 18px;
}

.table-wrap {
    overflow-x: auto;
    border-radius: var(--radius-lg);
}

table {
    width: 100%;
    border-collapse: collapse;
    min-width: 950px;
    overflow: hidden;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
}

th, td {
    padding: 14px 16px;
    text-align: left;
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
    vertical-align: top;
}

th {
    color: #dbe6ff;
    font-size: 0.92rem;
    background: rgba(255, 255, 255, 0.04);
}

.badge {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 7px 11px;
    border-radius: 999px;
    font-size: 0.8rem;
    font-weight: 700;
    background: rgba(79, 140, 255, 0.12);
    border: 1px solid rgba(79, 140, 255, 0.18);
}

.badge.active {
    background: rgba(38, 194, 129, 0.14);
    border-color: rgba(38, 194, 129, 0.22);
}

.badge.draft {
    background: rgba(245, 165, 36, 0.14);
    border-color: rgba(245, 165, 36, 0.22);
}

.badge.closed {
    background: rgba(255, 93, 93, 0.12);
    border-color: rgba(255, 93, 93, 0.18);
}

.question-card,
.question-block {
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 18px;
    margin-bottom: 16px;
}

.answer-box {
    margin-top: 14px;
    padding: 16px;
    border-radius: 16px;
    background: rgba(0, 0, 0, 0.18);
    border: 1px solid rgba(255, 255, 255, 0.08);
}

.answer-text {
    margin-top: 8px;
    white-space: pre-wrap;
    color: #d7e4ff;
}

.checkbox-line {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-top: 14px;
}

.checkbox-line input {
    width: auto;
}

.mcq-list {
    display: grid;
    gap: 12px;
    margin-top: 14px;
}

.mcq-option {
    display: flex;
    gap: 12px;
    align-items: center;
    padding: 14px 16px;
    border-radius: 14px;
    border: 1px solid var(--border);
    background: rgba(255, 255, 255, 0.04);
}

.mcq-option:hover {
    background: rgba(255, 255, 255, 0.07);
}

.mcq-option input {
    width: auto;
}

.exam-shell {
    max-width: 1280px;
    margin: 0 auto;
}

.exam-topbar {
    position: sticky;
    top: 84px;
    z-index: 10;
    display: grid;
    grid-template-columns: 1.5fr 0.7fr 1fr;
    gap: 16px;
    align-items: center;
    margin-bottom: 18px;
    padding: 20px;
    border-radius: var(--radius-xl);
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid var(--border);
    box-shadow: var(--shadow);
    backdrop-filter: blur(18px);
}

.timer-box {
    padding: 18px;
    text-align: center;
    border-radius: 18px;
    background: linear-gradient(135deg, rgba(79, 140, 255, 0.18), rgba(110, 168, 255, 0.10));
    border: 1px solid rgba(79, 140, 255, 0.20);
}

.timer-box #timer {
    margin-top: 6px;
    font-size: 2rem;
    font-weight: 800;
    letter-spacing: 0.5px;
}

.loader {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    border: 4px solid rgba(255, 255, 255, 0.12);
    border-top-color: var(--primary);
    animation: spin 1s linear infinite;
    margin-top: 14px;
}

/* Enhanced loaders */
.loader-small {
    width: 24px;
    height: 24px;
    border-width: 3px;
}

.loader-large {
    width: 64px;
    height: 64px;
    border-width: 5px;
}

/* Dots loader */
.loader-dots {
    display: flex;
    gap: 8px;
    justify-content: center;
    align-items: center;
}

.loader-dots span {
    width: 12px;
    height: 12px;
    border-radius: 50%;
    background: var(--primary);
    animation: bounce 1.4s ease-in-out infinite;
}

.loader-dots span:nth-child(1) { animation-delay: -0.32s; }
.loader-dots span:nth-child(2) { animation-delay: -0.16s; }

@keyframes bounce {
    0%, 80%, 100% { transform: scale(0); }
    40% { transform: scale(1); }
}

/* Pulse loader */
.loader-pulse {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    background: var(--primary);
    animation: pulse 1.5s ease-in-out infinite;
}

@keyframes pulse {
    0% { transform: scale(0.95); opacity: 1; }
    50% { transform: scale(1.1); opacity: 0.7; }
    100% { transform: scale(0.95); opacity: 1; }
}

/* Skeleton loading */
.skeleton {
    background: linear-gradient(90deg, rgba(255,255,255,0.05) 25%, rgba(255,255,255,0.1) 50%, rgba(255,255,255,0.05) 75%);
    background-size: 200% 100%;
    animation: shimmer 1.5s infinite;
    border-radius: 8px;
}

@keyframes shimmer {
    0% { background-position: 200% 0; }
    100% { background-position: -200% 0; }
}

.skeleton-text {
    height: 16px;
    margin-bottom: 8px;
}

.skeleton-title {
    height: 28px;
    width: 60%;
    margin-bottom: 16px;
}

.skeleton-card {
    height: 120px;
    margin-bottom: 16px;
}

@keyframes spin {
    to { transform: rotate(360deg); }
}

.actions {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
}

/* Toast notifications */
.toast-container {
    position: fixed;
    top: 20px;
    right: 20px;
    z-index: 1000;
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.toast {
    min-width: 300px;
    padding: 16px 20px;
    border-radius: var(--radius-lg);
    background: rgba(255, 255, 255, 0.95);
    border: 1px solid var(--border);
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
    backdrop-filter: blur(10px);
    animation: slideIn 0.3s ease;
    display: flex;
    align-items: center;
    gap: 12px;
    color: var(--text);
}

.toast.success {
    border-left: 4px solid var(--success);
}

.toast.error {
    border-left: 4px solid var(--danger);
}

.toast.warning {
    border-left: 4px solid var(--warning);
}

.toast.info {
    border-left: 4px solid var(--primary);
}

.toast.hiding {
    animation: slideOut 0.3s ease forwards;
}

@keyframes slideIn {
    from {
        transform: translateX(400px);
        opacity: 0;
    }
    to {
        transform: translateX(0);
        opacity: 1;
    }
}

@keyframes slideOut {
    from {
        transform: translateX(0);
        opacity: 1;
    }
    to {
        transform: translateX(400px);
        opacity: 0;
    }
}

/* Enhanced card animations */
.card {
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid var(--border);
    border-radius: var(--radius-xl);
    padding: 24px;
    box-shadow: var(--shadow);
    backdrop-filter: blur(18px);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.card:hover {
    transform: translateY(-4px);
    box-shadow: 0 24px 72px rgba(0, 0, 0, 0.45);
}

/* Progress bar */
.progress-bar {
    width: 100%;
    height: 8px;
    background: rgba(255, 255, 255, 0.1);
    border-radius: 999px;
    overflow: hidden;
}

.progress-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--primary), var(--primary-2));
    border-radius: 999px;
    transition: width 0.5s ease;
    animation: progressGlow 2s ease-in-out infinite;
}

@keyframes progressGlow {
    0%, 100% { opacity: 1; }
    50% { opacity: 0.8; }
}

/* Question palette */
.question-palette {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(48px, 1fr));
    gap: 8px;
    padding: 16px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    margin-bottom: 20px;
}

.palette-item {
    width: 48px;
    height: 48px;
    border-radius: 12px;
    display: grid;
    place-items: center;
    font-weight: 700;
    font-size: 0.9rem;
    cursor: pointer;
    transition: all 0.2s ease;
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid var(--border);
    color: var(--text);
}

.palette-item:hover {
    transform: scale(1.1);
    background: rgba(255, 255, 255, 0.1);
}

.palette-item.answered {
    background: rgba(38, 194, 129, 0.2);
    border-color: var(--success);
    color: var(--success);
}

.palette-item.review {
    background: rgba(245, 165, 36, 0.2);
    border-color: var(--warning);
    color: var(--warning);
}

.palette-item.current {
    background: var(--primary);
    border-color: var(--primary);
    color: white;
    transform: scale(1.1);
}

.palette-item.visited {
    background: rgba(79, 140, 255, 0.15);
    border-color: var(--primary);
}

/* Word counter */
.word-counter {
    text-align: right;
    font-size: 0.85rem;
    color: var(--muted);
    margin-top: 6px;
}

.word-counter.warning {
    color: var(--warning);
}

.word-counter.danger {
    color: var(--danger);
}

/* Timer states */
.timer-box.warning {
    background: linear-gradient(135deg, rgba(245, 165, 36, 0.18), rgba(250, 180, 50, 0.10));
    border-color: rgba(245, 165, 36, 0.30);
    animation: pulse 1s ease-in-out infinite;
}

.timer-box.danger {
    background: linear-gradient(135deg, rgba(255, 93, 93, 0.18), rgba(255, 70, 70, 0.10));
    border-color: rgba(255, 93, 93, 0.30);
    animation: urgentPulse 0.5s ease-in-out infinite;
}

@keyframes urgentPulse {
    0%, 100% { transform: scale(1); }
    50% { transform: scale(1.05); }
}

/* Auto-save indicator */
.auto-save-indicator {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    font-size: 0.85rem;
    color: var(--muted);
    padding: 6px 12px;
    border-radius: 999px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    transition: all 0.3s ease;
}

.auto-save-indicator.saving {
    color: var(--primary);
    border-color: rgba(79, 140, 255, 0.3);
}

.auto-save-indicator.saved {
    color: var(--success);
    border-color: rgba(38, 194, 129, 0.3);
}

/* Theme toggle button */
.theme-toggle {
    width: 44px;
    height: 44px;
    border-radius: 12px;
    display: grid;
    place-items: center;
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid var(--border);
    cursor: pointer;
    transition: all 0.3s ease;
    color: var(--text);
}

.theme-toggle:hover {
    background: rgba(255, 255, 255, 0.1);
    transform: rotate(180deg);
}

/* Mobile menu */
.mobile-menu-btn {
    display: none;
    width: 44px;
    height: 44px;
    border-radius: 12px;
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid var(--border);
    cursor: pointer;
    align-items: center;
    justify-content: center;
    gap: 6px;
    flex-direction: column;
}

.mobile-menu-btn span {
    width: 20px;
    height: 2px;
    background: var(--text);
    border-radius: 2px;
    transition: all 0.3s ease;
}

/* Page transitions */
.page-transition {
    animation: fadeIn 0.4s ease;
}

@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Button ripple effect */
.btn {
    position: relative;
    overflow: hidden;
}

.btn::after {
    content: '';
    position: absolute;
    top: 50%;
    left: 50%;
    width: 0;
    height: 0;
    background: rgba(255, 255, 255, 0.3);
    border-radius: 50%;
    transform: translate(-50%, -50%);
    transition: width 0.6s, height 0.6s;
}

.btn:active::after {
    width: 300px;
    height: 300px;
}

/* Stat card enhancements */
.stat-box {
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    padding: 18px;
    transition: all 0.3s ease;
}

.stat-box:hover {
    transform: translateY(-4px);
    background: rgba(255, 255, 255, 0.08);
    border-color: rgba(79, 140, 255, 0.3);
}

.stat-value {
    font-size: 2rem;
    font-weight: 800;
    margin: 8px 0;
    background: linear-gradient(135deg, var(--primary), var(--primary-2));
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
}

.stat-label {
    font-size: 0.9rem;
    color: var(--muted);
}

/* Chart container */
.chart-container {
    position: relative;
    height: 300px;
    margin-top: 20px;
}

/* Violation timeline */
.violation-timeline {
    position: relative;
    padding-left: 30px;
}

.violation-timeline::before {
    content: '';
    position: absolute;
    left: 8px;
    top: 0;
    bottom: 0;
    width: 2px;
    background: var(--border);
}

.violation-item {
    position: relative;
    padding: 12px 16px;
    margin-bottom: 12px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    border-radius: var(--radius-md);
}

.violation-item::before {
    content: '';
    position: absolute;
    left: -22px;
    top: 50%;
    transform: translateY(-50%);
    width: 12px;
    height: 12px;
    border-radius: 50%;
    background: var(--danger);
    border: 2px solid var(--bg);
}

.violation-item.warning::before {
    background: var(--warning);
}

.violation-time {
    font-size: 0.85rem;
    color: var(--muted);
    margin-bottom: 4px;
}

/* Activity feed */
.activity-feed {
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.activity-item {
    display: flex;
    gap: 12px;
    padding: 12px;
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid var(--border);
    border-radius: var(--radius-md);
    transition: all 0.2s ease;
}

.activity-item:hover {
    background: rgba(255, 255, 255, 0.06);
}

.activity-icon {
    width: 40px;
    height: 40px;
    border-radius: 10px;
    display: grid;
    place-items: center;
    background: rgba(79, 140, 255, 0.15);
    color: var(--primary);
    font-weight: 700;
    flex-shrink: 0;
}

.activity-content {
    flex: 1;
}

.activity-title {
    font-weight: 600;
    margin-bottom: 4px;
}

.activity-time {
    font-size: 0.85rem;
    color: var(--muted);
}

/* Search input */
.search-input {
    position: relative;
}

.search-input input {
    padding-left: 44px;
}

.search-input::before {
    content: '';
    position: absolute;
    left: 14px;
    top: 50%;
    transform: translateY(-50%);
    font-size: 1rem;
}

/* Dropdown */
.dropdown {
    position: relative;
    display: inline-block;
}

.dropdown-menu {
    position: absolute;
    top: 100%;
    right: 0;
    min-width: 200px;
    padding: 8px 0;
    background: rgba(255, 255, 255, 0.95);
    border: 1px solid var(--border);
    border-radius: var(--radius-lg);
    box-shadow: var(--shadow);
    backdrop-filter: blur(10px);
    opacity: 0;
    visibility: hidden;
    transform: translateY(-10px);
    transition: all 0.2s ease;
    z-index: 100;
}

.dropdown.active .dropdown-menu {
    opacity: 1;
    visibility: visible;
    transform: translateY(8px);
}

.dropdown-item {
    padding: 10px 16px;
    cursor: pointer;
    transition: background 0.2s ease;
    color: var(--text);
}

.dropdown-item:hover {
    background: rgba(79, 140, 255, 0.1);
}

.dropdown-divider {
    height: 1px;
    background: var(--border);
    margin: 8px 0;
}

/* Modal */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.7);
    backdrop-filter: blur(4px);
    display: grid;
    place-items: center;
    z-index: 1000;
    opacity: 0;
    visibility: hidden;
    transition: all 0.3s ease;
}

.modal-overlay.active {
    opacity: 1;
    visibility: visible;
}

.modal {
    background: var(--panel-solid);
    border: 1px solid var(--border);
    border-radius: var(--radius-xl);
    padding: 32px;
    max-width: 500px;
    width: 90%;
    transform: scale(0.9);
    transition: transform 0.3s ease;
}

.modal-overlay.active .modal {
    transform: scale(1);
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 20px;
}

.modal-close {
    width: 36px;
    height: 36px;
    border-radius: 10px;
    display: grid;
    place-items: center;
    background: rgba(255, 255, 255, 0.06);
    border: 1px solid var(--border);
    cursor: pointer;
    transition: all 0.2s ease;
}

.modal-close:hover {
    background: rgba(255, 93, 93, 0.2);
    border-color: var(--danger);
}

/* Tabs */
.tabs {
    display: flex;
    gap: 4px;
    padding: 4px;
    background: rgba(255, 255, 255, 0.04);
    border-radius: var(--radius-lg);
    margin-bottom: 20px;
}

.tab {
    flex: 1;
    padding: 12px 16px;
